'use client';

import * as React from 'react';
import { mockProjects } from '@/lib/mock-data';
import type { Project } from '@/lib/types';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from '@/components/ui/table';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { 
  MoreHorizontal, 
  Edit, 
  CheckCircle, 
  XCircle, 
  Users,
  Eye,
  Trash2
} from 'lucide-react';
import Link from 'next/link';

export default function AdminProyectosPage() {
  const [projects, setProjects] = React.useState<Project[]>(mockProjects);

  const getStatusBadgeVariant = (status: Project['status']) => {
    switch (status) {
      case 'En desarrollo':
        return 'default';
      case 'En lista de espera':
        return 'secondary';
      case 'En revisión':
        return 'outline';
      case 'Finalizado':
        return 'default';
      case 'Rechazado con retroalimentación':
        return 'destructive';
      case 'Borrador':
        return 'secondary';
      default:
        return 'secondary';
    }
  };

  const handleStatusChange = (projectId: string, newStatus: Project['status']) => {
    setProjects(prev => 
      prev.map(p => p.id === projectId ? { ...p, status: newStatus } : p)
    );
    // TODO: Aquí harías la llamada a la API para actualizar el estado
  };

  const handleDelete = (projectId: string) => {
    if (confirm('¿Estás seguro de que deseas eliminar este proyecto?')) {
      setProjects(prev => prev.filter(p => p.id !== projectId));
      // TODO: Aquí harías la llamada a la API para eliminar
    }
  };

  const stats = {
    total: projects.length,
    enDesarrollo: projects.filter(p => p.status === 'En desarrollo').length,
    enRevision: projects.filter(p => p.status === 'En revisión').length,
    finalizados: projects.filter(p => p.status === 'Finalizado').length,
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight font-headline">Gestión de Proyectos</h1>
        <p className="text-muted-foreground">
          Administra todos los proyectos del sistema: edita, cambia estados, gestiona integrantes.
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Proyectos</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.total}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">En Desarrollo</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.enDesarrollo}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">En Revisión</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.enRevision}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Finalizados</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.finalizados}</div>
          </CardContent>
        </Card>
      </div>

      {/* Projects Table */}
      <Card>
        <CardHeader>
          <CardTitle>Todos los Proyectos</CardTitle>
          <CardDescription>
            Listado completo de proyectos con opciones de gestión
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Título</TableHead>
                <TableHead>Solicitante</TableHead>
                <TableHead>Categoría</TableHead>
                <TableHead>Estado</TableHead>
                <TableHead>Integrantes</TableHead>
                <TableHead className="text-right">Acciones</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {projects.map((project) => (
                <TableRow key={project.id}>
                  <TableCell className="font-medium">
                    <div className="flex flex-col">
                      <span>{project.title}</span>
                      <span className="text-xs text-muted-foreground line-clamp-1">
                        {project.abstract}
                      </span>
                    </div>
                  </TableCell>
                  <TableCell>{project.solicitante.name}</TableCell>
                  <TableCell>
                    <Badge variant="outline">{project.category}</Badge>
                  </TableCell>
                  <TableCell>
                    <Badge variant={getStatusBadgeVariant(project.status)}>
                      {project.status}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-1">
                      <Users className="h-4 w-4 text-muted-foreground" />
                      <span className="text-sm">
                        {project.studentsEnrolled.length} / {project.studentLimit}
                      </span>
                    </div>
                  </TableCell>
                  <TableCell className="text-right">
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button variant="ghost" className="h-8 w-8 p-0">
                          <span className="sr-only">Abrir menú</span>
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Acciones</DropdownMenuLabel>
                        <DropdownMenuItem asChild>
                          <Link href={`/estudiante/proyectos/${project.id}`}>
                            <Eye className="mr-2 h-4 w-4" />
                            Ver detalles
                          </Link>
                        </DropdownMenuItem>
                        <DropdownMenuItem>
                          <Edit className="mr-2 h-4 w-4" />
                          Editar proyecto
                        </DropdownMenuItem>
                        <DropdownMenuItem>
                          <Users className="mr-2 h-4 w-4" />
                          Gestionar integrantes
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuLabel>Cambiar Estado</DropdownMenuLabel>
                        <DropdownMenuItem onClick={() => handleStatusChange(project.id, 'En desarrollo')}>
                          <CheckCircle className="mr-2 h-4 w-4" />
                          En desarrollo
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleStatusChange(project.id, 'En revisión')}>
                          <Eye className="mr-2 h-4 w-4" />
                          En revisión
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleStatusChange(project.id, 'Finalizado')}>
                          <CheckCircle className="mr-2 h-4 w-4 text-green-600" />
                          Marcar como finalizado
                        </DropdownMenuItem>
                        <DropdownMenuItem onClick={() => handleStatusChange(project.id, 'En lista de espera')}>
                          En lista de espera
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem 
                          className="text-destructive"
                          onClick={() => handleDelete(project.id)}
                        >
                          <Trash2 className="mr-2 h-4 w-4" />
                          Eliminar
                        </DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}
